VALUES
  ('heelevel3-7c4986e7-moex-00275', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列關於取得客戶合約之增額成本敘述，何者錯誤？', '["取得合約之增額成本係企業為取得客戶合約所發生且若未取得該合約則不會發生之成本", "企業若預期可回收其取得客戶合約之增額成本，企業應將該等成本認列為資產", "取得客戶合約之增額成本所認列之資產須攤銷並評估減損", "作為一實務權宜作法，對於取得合約之增額成本認列之資產，企業可將取得合約之增額成 本於發生時認列為費用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00276', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '乙公司是一家經營餐廳的營利事業，因為看好房地產景氣，在房地合一稅制實施後買入土地 並分類為投資性不動產，後續衡量採用公允價值模式，若該土地有公允價值變動之增值利益， 下列敘述何者正確？', '["所得稅費用增加、保留盈餘增加", "本期其他綜合淨利增加、其他權益增加", "遞延所得稅負債增加、保留盈餘減少", "本期所得稅負債增加、本期綜合淨利增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00277', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '乙公司於X1年12月30日將收到的承銷品列為進貨，並記入期末存貨，將使本期財務報表：', '["淨利低估，流動資產高估", "淨利低估，流動負債高估", "流動資產高估，流動負債高估", "不受影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00278', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '丙公司於X2年1月1日發行面額$100,000、利率11%、每年底付息一次、10年期公司債。 丙公司X5年1月1日應付公司債未攤銷折價的餘額為$4,564，X5年12月31日資產負債表 顯示應付公司債帳面金額為$95,888。請問該公司債之有效利率為何？（答案四捨五入至小數 點後二位）', '["13%", "15%", "10%", "12%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00279', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '某資訊顧問公司，於X1年初接獲客戶2年期之資訊安全專案服務，合約包價為1,000萬元， 估計總完工成本為600萬元，至X1年底已投入成本300萬元。請問該資訊顧問公司對此專 案服務於X1年可能認列收入若干元？ 甲、$0 乙、300萬元 丙、500萬元', '["僅丙正確", "僅乙、丙可能正確", "僅甲、乙可能正確", "甲、乙、丙均可能正確"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00280', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司為製造工業用材料的化學公司，因不慎排放廢水污染到工廠附近的下水道，引起當地 居民的抗議並提起訴訟要求賠償。由於已經被環保單位認定為有潛在責任的一方，甲公司的 管理當局與法律顧問評估此案件很有可能要賠償相關損害。經法律顧問的評估，訴訟判決損 害賠償的金額可能介於$2,000,000至$5,000,000間，再根據過去的判決案例，法律顧問認為最 有可能的賠償金額為$4,000,000。請問甲公司除附註揭露該事項及可能損失外，應在資產負債 表中認列之負債準備為何？', '["$2,000,000", "$3,500,000", "$4,000,000", "$5,000,000 32470"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00281', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司X1年12月31日流通在外普通股股數750,000股。於X2年7月1日現金增資發行450,000 股（無紅利因子）。甲公司於X2年初亦有股票選擇權流通在外，持有人得以每股$25購買300,000 股普通股，此股票選擇權於 X2 年底並未被執行。假設甲公司 X2 年全年度普通股平均市價為 $32，試問甲公司於計算X2年稀釋每股盈餘所使用之加權平均流通在外股數為：', '["975,000", "1,040,625", "1,209,375", "1,275,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00282', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列有關於投資性不動產之會計處理，何者錯誤？', '["投資性不動產購入時，應以成本衡量", "目前尚未確定將來用途的土地，屬於投資性不動產", "投資性不動產認列後選用公允價值模式衡量，不得改為成本模式", "企業將不動產出租給母公司或其他子公司，在編製合併報表時，該不動產應列為投資性不 動產"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00283', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '乙公司X3年期初現金餘額與期末現金餘額分別為$175,000與$205,000，X3年度投資活動現 金淨流入$300,000，籌資活動現金淨流出$420,000，折舊費用$37,000，出售設備利益$5,000， 應收帳款減少數$48,000，存貨增加數$12,000，應付帳款增加數$30,000，應付所得稅減少數 $7,000，支付所得稅$85,000。若乙公司將所得稅歸類於營業活動，請問乙公司 X3 年度本期 淨利為何？', '["$85,000", "$137,000", "$59,000", "$104,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00284', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-110-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司成立於X1年年初，核准發行面額$10之普通股800,000股。X1年12月31日的資產 負債表顯示，普通股股本為$4,000,000、普通股發行溢價為$2,400,000與保留盈餘為$800,000。 X2年9月1日，甲公司以每股$15收回庫藏股票30,000股，後續兩次出售該批庫藏股票分別 於X2年11月1日以每股$10出售12,000股與X2年12月1日以每股$17出售6,000股。X2 年 12 月 31 日的資產負債表顯示保留盈餘為$1,250,250。若甲公司保留盈餘之變動除前述交 易之可能影響外均來自淨利，請問X1年度與X2年度甲公司的每股盈餘為何？（答案四捨五 入至小數點後一位）', '["$1與$1.5", "$2與$1.3", "$1與$1.3", "$2與$1.5"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:27+00:00", "source_pdf_sha1": "54adefc2b8aa", "answer_pdf_sha1": "d506aee78b07", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "324", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
